```javascript
function fixWith2DPeriod(content, vPeriod, hPeriod) {
  const H = content.length;
  const W = content[0].length;
  const buckets = {};
  for (let r = 0; r < H; r++) {
    for (let c = 0; c < W; c++) {
      const key = `${r % vPeriod},${c % hPeriod}`;
      if (!buckets[key]) buckets[key] = {};
      buckets[key][content[r][c]] = (buckets[key][content[r][c]] || 0) + 1;
    }
  }
  const result = [];
  for (let r = 0; r < H; r++) {
    const row = [];
    for (let c = 0; c < W; c++) {
      const key = `${r % vPeriod},${c % hPeriod}`;
      const majority = Object.entries(buckets[key]).sort((a, b) => b[1] - a[1])[0][0];
      row.push(+majority);
    }
    result.push(row);
  }
  return result;
}

function findBest2DPeriod(content) {
  const H = content.length;
  const W = content[0].length;

  // For each candidate (vp, hp), check if majority-vote fix is perfectly periodic
  // AND changes fewer than half the cells (the pattern should be mostly correct)
  // Prefer smallest vp*hp (simplest pattern)

  for (let size = 1; size <= H * W; size++) {
    for (let vp = 1; vp <= Math.min(H, size); vp++) {
      for (let hp = 1; hp <= Math.min(W, size); hp++) {
        if (vp * hp !== size) continue;

        const fixed = fixWith2DPeriod(content, vp, hp);

        // Check if result is perfectly periodic
        let periodic = true;
        for (let r = 0; r < H && periodic; r++) {
          for (let c = 0; c < W && periodic; c++) {
            if (fixed[r][c] !== fixed[r % vp][c % hp]) periodic = false;
          }
        }
        if (!periodic) continue;

        // Check that we're not changing too many cells
        let changes = 0;
        for (let r = 0; r < H; r++) {
          for (let c = 0; c < W; c++) {
            if (fixed[r][c] !== content[r][c]) changes++;
          }
        }

        // The period should explain most of the data
        const total = H * W;
        if (changes < total * 0.2) { // less than 20% changes
          return { vp, hp, changes, total };
        }
      }
    }
  }
